  1	import { Dropdown, DropdownItem, Flex, MenuToggle, MenuToggleElement, Radio, Tooltip } from '@patternfly/react-core';
  2	import * as React from 'react';
  3	import { useTranslation } from 'react-i18next';
  4	import { Config } from '../../../model/config';
  5	import { FilterDefinition, FilterId } from '../../../model/filters';
  6	import { Match } from '../../../model/flow-query';
  7	import { findFilter } from '../../../utils/filter-definitions';
  8	import { isLokiLabel, swapFilterDefinition } from '../../../utils/filters-helper';
  9	import { useOutsideClickEvent } from '../../../utils/outside-hook';
 10	import { Direction } from '../filters-toolbar';
 11	import './filters-dropdown.css';
 12	
 13	export interface FiltersDropdownProps {
 14	  config: Config;
 15	  filterDefinitions: FilterDefinition[];
 16	  selectedDirection: Direction;
 17	  setSelectedDirection: (v: Direction) => void;
 18	  selectedFilter: FilterDefinition;
 19	  setSelectedFilter: (f: FilterDefinition | null | undefined) => void;
 20	  match?: Match;
 21	}
 22	
 23	export const FiltersDropdown: React.FC<FiltersDropdownProps> = ({
 24	  config,
 25	  filterDefinitions,
 26	  selectedDirection,
 27	  setSelectedDirection,
 28	  selectedFilter,
 29	  setSelectedFilter,
 30	  match
 31	}) => {
 32	  const { t } = useTranslation('plugin__netobserv-plugin');
 33	
 34	  const columnRef = useOutsideClickEvent(() => setColumnOpen(false));
 35	  const [isColumnOpen, setColumnOpen] = React.useState<boolean>(false);
 36	
 37	  const getFiltersDropdownItems = React.useCallback(() => {
 38	    return filterDefinitions
 39	      .filter(f => !f.category || f.category === 'endpoint')
 40	      .sort((a, b) => a.name.localeCompare(b.name))
 41	      .map((f, index) => (
 42	        <DropdownItem
 43	          data-test={f.id}
 44	          id={f.id}
 45	          className={`column-filter-item`}
 46	          component="button"
 47	          onClick={() => {
 48	            setColumnOpen(false);
 49	            setSelectedFilter(f);
 50	          }}
 51	          key={index}
 52	        >
 53	          {isLokiLabel(f, config) ? <strong>{f.name}</strong> : f.name}
 54	        </DropdownItem>
 55	      ));
 56	  }, [config, filterDefinitions, setSelectedFilter]);
 57	
 58	  const onRadioChange = React.useCallback(
 59	    (event: React.FormEvent<HTMLInputElement>, checked: boolean) => {
 60	      if (checked) {
 61	        const name = event.currentTarget.name;
 62	        if (name === 'either') {
 63	          setSelectedDirection(undefined);
 64	        } else {
 65	          setSelectedDirection(name as Direction);
 66	        }
 67	      }
 68	    },
 69	    [setSelectedDirection]
 70	  );
 71	
 72	  React.useEffect(() => {
 73	    if (selectedDirection) {
 74	      const dir = selectedDirection === 'source' ? 'src' : 'dst';
 75	      if (selectedFilter.category) {
 76	        setSelectedFilter(swapFilterDefinition(filterDefinitions, selectedFilter, dir));
 77	      } else {
 78	        setSelectedDirection(undefined);
 79	      }
 80	    } else if (selectedFilter.id.startsWith('src_') || selectedFilter.id.startsWith('dst_')) {
 81	      const id = selectedFilter.id.replace('src_', '').replace('dst_', '') as FilterId;
 82	      setSelectedFilter(findFilter(filterDefinitions, id));
 83	    }
 84	  }, [filterDefinitions, selectedDirection, selectedFilter, setSelectedDirection, setSelectedFilter]);
 85	  return (
 86	    <Flex id="direction-column-filter-dropdowns">
 87	      <div id="column-filter-dropdown-container" data-test="column-filter-dropdown-container" ref={columnRef}>
 88	        <Tooltip
 89	          content={
 90	            <div>
 91	              {t('Select a field name to filter on. Use indexed fields in bold to improve your query performances.')}
 92	            </div>
 93	          }
 94	          isVisible={isColumnOpen}
 95	          enableFlip={false}
 96	          position={'top'}
 97	        >
 98	          <Dropdown
 99	            data-test="column-filter-dropdown"
100	            id="column-filter-dropdown"
101	            isOpen={isColumnOpen}
102	            isScrollable
103	            toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
104	              <MenuToggle
105	                ref={toggleRef}
106	                data-test="column-filter-toggle"
107	                id="column-filter-toggle"
108	                onClick={() => {
109	                  setColumnOpen(!isColumnOpen);
110	                }}
111	                isExpanded={isColumnOpen}
112	              >
113	                {selectedFilter.name}
114	              </MenuToggle>
115	            )}
116	          >
117	            {getFiltersDropdownItems()}
118	          </Dropdown>
119	        </Tooltip>
120	      </div>
121	      <div id="direction-filter-dropdown-container" data-test="column-filter-dropdown-container">
122	        <Radio
123	          id="radio-source"
124	          data-test="radio-source"
125	          label={match === 'bidirectional' ? t('As endpoint A') : t('As source')}
126	          name="source"
127	          isChecked={selectedDirection === 'source'}
128	          onChange={onRadioChange}
129	          isDisabled={!selectedFilter.category}
130	        />
131	        <Radio
132	          id="radio-destination"
133	          data-test="radio-destination"
134	          label={match === 'bidirectional' ? t('As endpoint B') : t('As destination')}
135	          name="destination"
136	          isChecked={selectedDirection === 'destination'}
137	          onChange={onRadioChange}
138	          isDisabled={!selectedFilter.category}
139	        />
140	        <Radio
141	          id="radio-either"
142	          data-test="radio-either"
143	          label={t('Either')}
144	          name="either"
145	          isChecked={!selectedDirection}
146	          onChange={onRadioChange}
147	          isDisabled={!selectedFilter.category || match === 'bidirectional'}
148	        />
149	      </div>
150	    </Flex>
151	  );
152	};
153	
154	export default FiltersDropdown;

